mutation AuthOrCaptureFunds {
  orderCreateMandatePayment(
    id: "gid://shopify/Order/6411651318016",
    idempotencyKey: "unique-key-here",
    mandateId: "gid://shopify/PaymentMandate/2366a89f1200930b8ba8a73f2c44396e",
    amount: {
      amount: 60.00,
      currencyCode: USD
    },
    autoCapture: true
    # false = auth only; true = auth and capture
  ) {
    paymentReferenceId
    userErrors {
      field
      message
    }
  }
}

mutation CaptureOrderPayment {
  orderCapture(
    input: {
      id: "gid://shopify/Order/6420485701888",
      amount: "70.00",
      currency: USD,
      parentTransactionId: "gid://shopify/OrderTransaction/7554172420352"
    }
  ) {
    transaction {
      id
      amountSet {
        shopMoney {
          amount
          currencyCode
        }
      }
      kind
      status
    }
    userErrors {
      field
      message
    }
  }
}

mutation CreateDraftOrder($inputDraftOrder: DraftOrderInput!) {
  draftOrderCreate(input: $inputDraftOrder) {
    draftOrder {
      id
      name
      status
    }
    userErrors {
      field
      message
    }
  }
}

mutation CompleteDraftOrder {
  draftOrderComplete(
    id: "gid://shopify/DraftOrder/1190739050752"
  ) {
    draftOrder {
      id
      order {
        id
        name
      }
    }
    userErrors {
      field
      message
    }
  }
}

mutation OrderCreate {
  orderCreate(
    order: {
      currency: USD,
      financialStatus: PENDING,
      companyLocationId: "gid://shopify/CompanyLocation/7751139584",
      lineItems: [
        {
          variantId: "gid://shopify/ProductVariant/46411477811456",
          quantity: 2
        }
      ],
      customer: {
        toAssociate: {
          id: "gid://shopify/Customer/8055141957888"
        }
      }
    }
  ) {
    order {
      id
    }
    userErrors {
      field
      message
    }
  }
}

mutation storeCreditAccountCredit {
  storeCreditAccountCredit(
    id: "gid://shopify/CompanyLocation/7751139584",
    creditInput: {
      creditAmount: {
        amount: "50.00",
        currencyCode: USD
      }
    }
  ) {
    storeCreditAccountTransaction {
      amount {
        amount
        currencyCode
      }
      account {
        id
        balance {
          amount
          currencyCode
        }
      }
    }
    userErrors {
      message
      field
    }
  }
}
